      private bool nxMapLayerGPU1_OnRender(NXImageLayerGPU sender, NXImageViewDrawArgs DrawArgs)
      {
          XGraphics g = DrawArgs.Graphics;
          XVertex3d vPos = new XVertex3d(127.0, 37.0, 0);
          double nOff = DrawArgs.PixelSize * 10;
          g.glColor3d(1, 0, 0);
          g.glBegin(XGraphics.GL_LINES);
          g.glVertex3d(vPos.x - nOff, vPos.y, vPos.z);
          g.glVertex3d(vPos.x + nOff, vPos.y, vPos.z);
          g.glVertex3d(vPos.x, vPos.y - nOff, vPos.z);
          g.glVertex3d(vPos.x, vPos.y + nOff, vPos.z);
          g.glEnd();

          DrawArgs.Invalidate();
          return default(bool);
      }

