          {
              double sx = Pixoneer.NXDL.XWndMsg.GetLowValue(m.LParam);
              double sy = Pixoneer.NXDL.XWndMsg.GetHighValue(m.LParam);

              XDMBand band = m_xrsFile.GetBandAt(0);
              double TmpFrameCenterEle = 30;
              XVertex3d ptGeo1 = new XVertex3d();
              XVertex3d ptGeo2 = new XVertex3d();

              XVertex2d bandPos = nxMapView1.ScreenToWorld(new XVertex2d(sx, sy));
              band.WorldToPixel(ref bandPos.x, ref bandPos.y);
              m_sm.ImageToWorldG(bandPos, TmpFrameCenterEle, out ptGeo2);
              System.Diagnostics.Debug.WriteLine("Pixel : ({2}, {3}) Geo Lat : {0}, Lon : {1}\n", ptGeo2.y, ptGeo2.x, bandPos.x, bandPos.y);

          }
          return default(bool);
      }


