        public static void updateViewGray(XDMBand band, NXImageLayerComposites compLayer)
        {
            updateViewGray(band, compLayer, eCompStretchCoverage.Visible, eCompStretchType.Linear, eCompCutType.Ct95, 0.5);
        }

        public static void updateViewGray(XDMBand band, NXImageLayerComposites compLayer, eCompStretchCoverage sc, eCompStretchType st, eCompCutType ct, double gamma)
        {
            // get XDMCompManager and reset list
            compLayer.Lock();
            XDMCompManager xdmCompManager = compLayer.GetXDMCompManager();
            for (int i = 0; i < xdmCompManager.NumComp; i++)
            {
                XDMComposite comp = xdmCompManager.GetXDMCompositeAt(i);
                comp.Dispose();
            }
            xdmCompManager.RemoveXDMCompositeAll();

            // XDMComposite를 생성하고 Band와 도시 방법을 설정
            XDMComposite newComp = new XDMComposite();

            newComp.Name = band.BandName;
            newComp.Mode = eCompMode.Gray;
            if (band.BandType == eBandType.GIS)
            {
                newComp.SetBandGIS(ref band);
            }
            else
            {
                newComp.SetBand(ref band, 0);
                newComp.SetCutType(ct, 0);
                newComp.SetStretchCoverage(sc, 0);
                newComp.SetStretchType(st, 0);
                newComp.SetGammaValue(gamma, 0);
            }


            xdmCompManager.AddXDMComposite(ref newComp);
            compLayer.ZoomFit();
            compLayer.Invalidate();
            compLayer.UnLock();
        }

        public void updateViewRGB(XDMBand bandR, XDMBand bandG, XDMBand bandB, NXImageLayerComposites compLayer)
        {
            updateViewRGB(bandR, bandG, bandB, compLayer, eCompStretchCoverage.Band, eCompStretchType.Linear, eCompCutType.Ct95);
        }

        public void updateViewRGB(XDMBand bandR, XDMBand bandG, XDMBand bandB, NXImageLayerComposites compLayer, eCompStretchCoverage sc, eCompStretchType st, eCompCutType ct)
        {
            compLayer.Lock();
            // get XDMCompManager and reset list
            XDMCompManager xdmCompManager = compLayer.GetXDMCompManager();
            for (int i = 0; i < xdmCompManager.NumComp; i++)
            {
                XDMComposite comp = xdmCompManager.GetXDMCompositeAt(i);
                comp.Dispose();
            }

           }
           xdmCompManager.RemoveXDMCompositeAll();

           // XDMComposite를 생성하고 Band와 도시 방법을 설정
           XDMComposite newComp = new XDMComposite();

           newComp.Mode = eCompMode.RGB;
           if (bandR != null) newComp.SetBand(ref bandR, 2);
           if (bandG != null) newComp.SetBand(ref bandG, 1);
           if (bandB != null) newComp.SetBand(ref bandB, 0);
           for (int i = 0; i < 3; i++)
           {
               newComp.SetCutType(ct, i);
               newComp.SetStretchCoverage(sc, i);
               newComp.SetStretchType(st, i);
           }

           xdmCompManager.AddXDMComposite(ref newComp);
           compLayer.ZoomFit();
           compLayer.Invalidate();
           compLayer.UnLock();
       }

       public static void updateViewFile(XRSLoadFile file, NXImageLayerComposites compLayer)
       {
           compLayer.Lock();
           // get XDMCompManager and reset list
           XDMCompManager xdmCompManager = compLayer.GetXDMCompManager();
           //for (int i = 0; i < xdmCompManager.NumComp; i++)
           //{
           //    XDMComposite comp = xdmCompManager.GetXDMCompositeAt(i);
           //    comp.Dispose();
           //}
           //xdmCompManager.RemoveXDMCompositeAll();

           // XDMComposite를 생성하고 Band와 도시방법을 설정
           XDMComposite newComp = new XDMComposite();
           int nNumBand = file.NumBand;
           if (nNumBand < 3)
           {
               XDMBand band = file.GetBandAt(0);
               newComp.Name = band.BandName;

               newComp.Mode = eCompMode.Gray;
               newComp.SetBand(ref band, 0);
               newComp.SetCutType(eCompCutType.Ct95, 0);
               newComp.SetStretchCoverage(eCompStretchCoverage.Band, 0);
               newComp.SetStretchType(eCompStretchType.Linear, 0);

           }
           else
           {
               XDMBand band1 = file.GetBandAt(0);
               XDMBand band2 = file.GetBandAt(1);
               XDMBand band3 = file.GetBandAt(2);
               newComp.Name = file.FileName;

               newComp.Mode = eCompMode.RGB;
               newComp.SetBand(ref band1, 2);
               newComp.SetBand(ref band2, 1);
               newComp.SetBand(ref band3, 0);

               for (int i = 0; i < 3; i++)
               {
                   newComp.SetCutType(eCompCutType.Ct95, i);
                   newComp.SetStretchCoverage(eCompStretchCoverage.Band, i);
                   newComp.SetStretchType(eCompStretchType.Linear, i);
               }
           }

           xdmCompManager.AddXDMComposite(ref newComp);
           // XSpatialReference sr = new XSpatialReference();
           //sr.SetCoordType(eCoordType.Pixel);
           //xdmCompManager.SetSR(ref sr);
           compLayer.ZoomFit();
           compLayer.Invalidate();
           compLayer.UnLock();
       }

       public static string MakeMousePosInfo(XDMBand band, int pixx, int pixy, NXImageView nxmapView)
       {
           double x, y;//, value;
           XVertex2d pos = nxmapView.ScreenToWorld(new XVertex2d(pixx, pixy));
           x = pos.x; y = pos.y;
           band.WorldToPixel(ref x, ref y);
           //value = band.ReadPixel()
           string textPos = string.Format("Pixel ({0:0}, {1:0}), World({2:0.00000000}, {3:0.00000000})", x, y, pos.x, pos.y);
           return textPos;
       }

