public void CopySettingFromView(ref NXImageView view, ref NXImageLayerComposites compLayer)
{
    // init composite layer
    compLayer.Lock();
    nxMapLayerComposites1.Lock();
    XDMCompManager srcCompMan = compLayer.GetXDMCompManager();
    XDMCompManager dstCompMan = nxMapLayerComposites1.GetXDMCompManager();

    for (int i = 0; i < srcCompMan.NumComp; i++)
    {
        XDMComposite comp = srcCompMan.GetXDMCompositeAt(i);
        dstCompMan.AddXDMComposite(ref comp);
    }
    nxMapLayerComposites1.UnLock();
    compLayer.UnLock();
    nxMapView1.ZoomFit();
    nxMapView1.RefreshScreen();

    // init view settings
    int screenOffset = 30; // center off = 30 pix
    double wpx = 0,wpy = 0;
    view.GetWorldPerScreen(ref wpx, ref wpy);
    XVertex2d vCenter = view.ScreenToWorld(new XVertex2d(view.Width / 2.0 + screenOffset, view.Height / 2.0 + screenOffset));

    nxMapView1.SetWorldToCenter(vCenter.x, vCenter.y);
    nxMapView1.RefreshScreen();
    System.Threading.Thread.Sleep(1000);

    nxMapView1.SetWorldPerScreen(wpx * 0.5, wpy * 0.5);
    nxMapView1.RefreshScreen();
    System.Threading.Thread.Sleep(1000);

    nxMapView1.SetRotationAngle(XAngle.FromDegree(45.0));
    nxMapView1.RefreshScreen();
    System.Threading.Thread.Sleep(1000);
}

