public static string MakeMousePosInfo(XDMBand band, int pixx, int pixy, NXImageView nxmapView)
{
    double x, y;//, value;
    XVertex2d pos = nxmapView.ScreenToWorld(new XVertex2d(pixx, pixy));
    x = pos.x; y = pos.y;
    band.WorldToPixel(ref x, ref y);
    //value = band.ReadPixel()
    string textPos = string.Format("Pixel ({0:0}, {1:0}), World({2:0.00000000}, {3:0.00000000})", x, y, pos.x, pos.y);
    return textPos;
}

