        private void trackBar_Contrast_Scroll(object sender, EventArgs e)
        {
            string strValue = trackBar_Contrast.Value.ToString();
            nxImageView.BackgroundMapContrast = float.Parse(strValue) / 50.0f;
            nxImageView.Invalidate();
        }

        private void trackBar_Brightness_Scroll(object sender, EventArgs e)
        {
            string strValue = trackBar_Brightness.Value.ToString();
            nxImageView.BackgroundMapBrightness = float.Parse(strValue) / 50.0f;
            Debug.WriteLine("BackgroundMapBrightness : " + nxImageView.BackgroundMapBrightness.ToString());

            nxImageView.Invalidate();
        }

        private void trackBar_Saturation_Scroll(object sender, EventArgs e)
        {
            string strValue = trackBar_Saturation.Value.ToString();
            nxImageView.BackgroundMapSaturation = float.Parse(strValue) / 50.0f;
            nxImageView.Invalidate();
        }

        private void button_goto_Click(object sender, EventArgs e)
        {

        }

        private void trackBar_Ratio_Scroll(object sender, EventArgs e)
        {
            string strValue = trackBar_Ratio.Value.ToString();
            nxImageView.BackgroundMapAlpha = float.Parse(strValue) / 100.0f;
            nxImageView.Invalidate();
        }

        private void button1_Click(object sender, EventArgs e)
        {
            OpenFileDialog openFileDialog = new OpenFileDialog();
            openFileDialog.Multiselect = false;
            openFileDialog.Filter = "Config file(*.xml)|*.xml||";
            openFileDialog.RestoreDirectory = true;
            if (openFileDialog.ShowDialog() != DialogResult.OK) return;

            string fileNameConfig = openFileDialog.FileName;
            textBoxConfigFileName.Text = fileNameConfig;

            nxImageView.SetBackgroundMap(fileNameConfig);
        }
    }
